public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    mw.ident(buf, indent);
    buf.append(type).append(' ');
    buf.append(name.name);
    if (initValue != null) {
        if (type.length() >= 16) {
            buf.append('\n');
            mw.ident(buf, indent + 2);
            buf.append("= ");
        } else {
            buf.append(" = ");
        }
        initValue.toString(mw, buf, indent);
    }
    buf.append(';');
}

public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    buf.append('(').append(type).append(") ");
    boolean quote = value instanceof OpBinary;
    if (quote) {
        buf.append('(');
    }
    value.toString(mw, buf, indent);
    if (quote) {
        buf.append(')');
    }
}

public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    buf.append("new ").append(type).append('(');
    for (int i = 0; i < args.length; i++) {
        if (i != 0) {
            buf.append(", ");
        }
        args[i].toString(mw, buf, indent);
    }
    buf.append(')');
}

