private String findConverterName(StructInfo structInfo, String suffix) {
    int dotIndex;
    dotIndex = structInfo.binaryName.lastIndexOf('$');
    if (dotIndex != -1) {
        dotIndex = structInfo.binaryName.lastIndexOf('.');
    }
    String className = structInfo.binaryName.substring(dotIndex + 1);
    if (dotIndex == -1) {
        return className + suffix;
    }
    String packageName = structInfo.binaryName.substring(0, dotIndex);
    return packageName + '.' + className + suffix;
}

public void required(String fieldName) {
    if (schema == null) {
        schema = JSONObject.of("required", JSONArray.of(fieldName)).toString();
    } else {
        JSONObject object = JSONObject.parseObject(schema);
        JSONArray array = object.getJSONArray("required");
        array.add(fieldName);
        schema = object.toString();
    }
}

public DateTimeFormatter getDateFormatter() {
    if (dateFormatter == null && format != null && !formatMillis && !formatISO8601 && !formatUnixTime) {
        if (locale == null) {
            dateFormatter = DateTimeFormatter.ofPattern(format);
        } else {
            dateFormatter = DateTimeFormatter.ofPattern(format, locale);
        }
    }
    return dateFormatter;
}

public <T extends Annotation> T getAnnotation(Class<T> annotationClass) {
    T annotation = null;
    if (method != null) {
        annotation = method.getAnnotation(annotationClass);
    }

    if (annotation == null && field != null) {
        annotation = field.getAnnotation(annotationClass);
    }

    return annotation;
}

