@Override
        public boolean apply(String label) {
            if (excludes != null) {
                return Arrays.binarySearch(excludes, label) < 0;
            }

            return includes != null && Arrays.binarySearch(includes, label) >= 0;
        }

static ValueFilter of(Predicate<String> nameMatcher, Function function) {
    return (object, fieldName, fieldValue)
            -> nameMatcher == null || nameMatcher.test(fieldName)
            ? function.apply(fieldValue)
            : fieldValue;
}

public static String type(Class<?> clazz) {
    String type = typeMapping.get(clazz);
    if (type != null) {
        return type;
    }

    if (clazz.isArray()) {
        return "[" + desc(clazz.getComponentType());
    }

    // 直接基于字符串替换，不使用正则替换
    return clazz.getName().replace('.', '/');
}

