final void put11(final int byteValue1, final int byteValue2) {
    int currentLength = length;
    if (currentLength + 2 > data.length) {
        enlarge(2);
    }
    byte[] currentData = data;
    currentData[currentLength++] = (byte) byteValue1;
    currentData[currentLength++] = (byte) byteValue2;
    length = currentLength;
}

public ByteVector putInt(final int intValue) {
    int currentLength = length;
    if (currentLength + 4 > data.length) {
        enlarge(4);
    }
    byte[] currentData = data;
    currentData[currentLength++] = (byte) (intValue >>> 24);
    currentData[currentLength++] = (byte) (intValue >>> 16);
    currentData[currentLength++] = (byte) (intValue >>> 8);
    currentData[currentLength++] = (byte) intValue;
    length = currentLength;
    return this;
}

private String readUTF8(int index, final char[] buf) {
    int item = readUnsignedShort(index);
    String s = strings[item];
    if (s != null) {
        return s;
    }
    index = items[item];
    return strings[item] = readUTF(index + 2, readUnsignedShort(index), buf);
}

protected void visitLocalVariable(String name, int index) {
    if (index >= ignoreCount && index < ignoreCount + paramCount) {
        if (!("arg" + currentParameter).equals(name)) {
            debugInfoPresent = true;
        }
        result.append(',');
        result.append(name);
        currentParameter++;
    }
}

private void visitIntInsn(final int opcode, final int operand) {
    lastBytecodeOffset = code.length;
    // Add the instruction to the bytecode of the method.
    if (opcode == Opcodes.SIPUSH) {
        code.put12(opcode, operand);
    } else { // BIPUSH or NEWARRAY
        code.put11(opcode, operand);
    }
    // If needed, update the maximum stack size and number of locals, and stack map frames.
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(opcode, operand, null, null);
    }
}

public void visitLdcInsn(final Number value) {
    if (value instanceof Integer) {
        visitLdcInsn(value.intValue());
    } else if (value instanceof Long) {
        visitLdcInsn(value.longValue());
    } else {
        throw new UnsupportedOperationException(value.getClass().getName());
    }
}
